#include <bits/stdc++.h>
using namespace std;
typedef long long ll;

const int N=6e6+10,mod=1e9+7;
const ll V=2e14;

struct Node{
	int res,lc,rc;
	ll sum,flow;
}t[N];

int m,tot=1;

int cal(ll l,ll r){
    l%=mod,r%=mod;
    return (l+r)*(r-l+1)/2%mod;
}

int Update(int cur,ll l,ll r,ll flow){
    if(t[cur].sum+flow>=r-l+1)
        return cal(l,r);
    if(flow==0)
        return t[cur].res;
    if(cur==0)
        return cal(l,l+flow-1);
    ll mid=l+r>>1;
    if(t[t[cur].lc].sum+flow<=mid-l+1)
        return (Update(t[cur].lc,l,mid,flow)+t[cur].res-t[t[cur].lc].res)%mod;
    else
        return (Update(t[cur].rc,mid+1,r,flow-(mid-l+1-t[t[cur].lc].sum)+t[t[cur].lc].flow)+cal(l,mid))%mod;
}

void Pushup(int p,ll l,ll r){
    ll mid=l+r>>1;
	t[p].sum=t[t[p].lc].sum+min(r-mid,t[t[p].rc].sum+t[t[p].lc].flow);
	t[p].flow=t[t[p].rc].flow+max(0ll,t[t[p].rc].sum+t[t[p].lc].flow-(r-mid));
	t[p].res=(t[t[p].lc].res+Update(t[p].rc,mid+1,r,t[t[p].lc].flow))%mod;
	// printf("%lld %lld %d %lld\n",l,r,t[p].res,t[p].sum);
}

void modify(int cur,ll l,ll r,ll x,int y){
	if(l==r){
		if(y){
			t[cur].res=l%mod;
			t[cur].sum=1,t[cur].flow=y-1;
		}else
			t[cur].res=t[cur].sum=t[cur].flow=0;
		return;
	}
	ll mid=l+r>>1;
	if(x<=mid){
		if(!t[cur].lc) t[cur].lc=++tot;
		modify(t[cur].lc,l,mid,x,y);
	}else{
		if(!t[cur].rc) t[cur].rc=++tot;
		modify(t[cur].rc,mid+1,r,x,y);
	}
	Pushup(cur,l,r);
}

int main(){
	scanf("%d",&m);
	while(m--){
		ll x;
		int y;
		scanf("%lld%d",&x,&y);
		modify(1,1,V,x,y);
		printf("%d\n",(t[1].res+mod)%mod);
	}
	return 0;
}
